SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_com_m_receipt ON sc_com_m_receipt CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_com_m_receipt() RETURNS trigger AS $BODY$
declare
 li_count integer;
BEGIN
  BEGIN
  --//--Insert  
  if coalesce(OLD.receipt_no::text, '') = ''  then 
    if pka.auto_entry then 
      --:new.membership_no เพลินจิต คีย์ไม่ถูกหรือยังงัยไม่รู้ เป็น 2 รอบแล้ว
      select size_member_no 
      into STRICT li_count 
      from sc_cnt_m_coop;

      if NEW.membership_no <> 'fundmem' and len(trim(both NEW.membership_no)) <> li_count then
        CALL spa_dberror('ทะเบียนสมาชิก ไม่ตรงตาม ฟอร์แมต');
      end if;
   --if pka.auto_entry then  
      if coalesce(NEW.entry_id::text, '') = '' then NEW.entry_id := current_setting('app.login_id', true);end if;
      if coalesce(NEW.branch_id::text, '') = '' then NEW.branch_id := current_setting('app.login_br', true);end if;
      NEW.entry_date := statement_timestamp();
      if coalesce(NEW.finance_date::text, '') = '' then NEW.finance_date := pka_fin_daily.fp_finance_date('1');end if;
    end if;

    -- ทุนเรือนหุ้นของสมาชิก ก่อนทำรายการ
    if coalesce(NEW.share_stock::text, '') = '' /*or :new.share_stock = 0 */
 then
      BEGIN 
        select share_stock into STRICT NEW.share_stock
        from sc_mem_m_share_mem 
        where membership_no = NEW.membership_no;
      exception when others then null;end;
      if coalesce(NEW.share_stock::text, '') = '' then NEW.share_stock :=0;end if;
    end if;
    -- หน่วยสมาชิก
    if coalesce(NEW.member_group_no::text, '') = '' then
      BEGIN
        select member_group_no into STRICT NEW.member_group_no
        from sc_mem_m_membership_registered
        where membership_no = NEW.membership_no;
      exception when others then null;end;
    end if;
  end if;
  --//--Cancel
  if OLD.receipt_status = '0' and NEW.receipt_status = '1' then
    NEW.cancel_id := current_setting('app.login_id', true);
    NEW.cancel_pc := pka_com_login.login_pc;
    NEW.cancel_branch := current_setting('app.login_br', true);
    NEW.cancel_date := statement_timestamp();
    NEW.finance_cancel := pka_fin_daily.fp_finance_date('1');
  end if;
  --//--Default
  if coalesce(NEW.magent_status::text, '') = '' or NEW.magent_status !='1' then NEW.magent_status :='0';end if;
  if coalesce(NEW.recept_amount::text, '') = '' then NEW.recept_amount  := 0;end if;

  -- ดอกเบี้ยสะสมของสมาชิก หลังชำระ (รวมกับดอกเบี้ยทุกรายการที่ชำระในใบเสร็จใบนี้)
  --if :new.total_interest is null then :new.total_interest := 0; end if; 
  -- ดอกเบี้ยสะสมของสมาชิก ก่อนทำรายการ
  if pka.auto_entry then
    NEW.TOTAL_INTEREST := pka_lon.fp_totalint_memno(NEW.membership_no);
  end if;
  if coalesce(NEW.total_interest::text, '') = '' then NEW.total_interest := 0;end if;
  if coalesce(NEW.receipt_status::text, '') = '' or NEW.receipt_status != '1' then NEW.receipt_status :='0';end if;
  if coalesce(NEW.money_trans_amount::text, '') = '' then NEW.money_trans_amount := 0;end if;
  if coalesce(NEW.money_trans_return::text, '') = '' then NEW.money_trans_return := 0;end if;
  if coalesce(NEW.ppm_status::text, '') = '' or NEW.ppm_status !='1' then NEW.ppm_status := '0';end if;
  if coalesce(NEW.share_arrear_pay::text, '') = '' then NEW.share_arrear_pay := 0;end if;
  if coalesce(NEW.fin_status::text, '') = '' or NEW.fin_status !='1' then NEW.fin_status :='0';end if;
  if coalesce(NEW.ppm_monthly::text, '') = '' or NEW.ppm_monthly !='1' then NEW.ppm_monthly :='0';end if;
  if coalesce(NEW.link_book_bank::text, '') = '' or NEW.link_book_bank != '1' then NEW.link_book_bank := '0';end if;
  if coalesce(NEW.link_recvpay::text, '') = '' or NEW.link_recvpay != '1' then NEW.link_recvpay := '0';end if;
  if coalesce(NEW.keep_monthly::text, '') = '' then NEW.keep_monthly :=0;end if;
  if coalesce(NEW.loan_fee::text, '') = '' or NEW.loan_fee != '1' then NEW.loan_fee := '0';end if;

  if coalesce(trim(both NEW.receipt_mode)::text, '') = ''  then NEW.receipt_mode := '0';end if;
  END;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_com_m_receipt() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_com_m_receipt
	BEFORE INSERT ON sc_com_m_receipt FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_com_m_receipt();

